const rpc = $input.first().json;
if (rpc.error) throw new Error('MCP transport error: ' + JSON.stringify(rpc.error));
if (rpc.result && rpc.result.isError) throw new Error('MCP tool error: ' + ((rpc.result.content && rpc.result.content[0] && rpc.result.content[0].text) || 'unknown'));
const slot = JSON.parse(rpc.result.content[0].text);
if (slot.error) throw new Error('request_file_upload: ' + slot.error);
const trigger = $('On form submission').first();
const binKey = Object.keys(trigger.binary || {})[0];
if (!binKey) throw new Error('No file arrived from the form.');
slot.openBody = { jsonrpc: '2.0', id: 2, method: 'tools/call', params: { name: 'open_pdf', arguments: { upload_token: slot.upload_token } } };
return [{ json: slot, binary: { file: trigger.binary[binKey] } }];

const rpc = $input.first().json;
if (rpc.error) throw new Error('MCP transport error: ' + JSON.stringify(rpc.error));
if (rpc.result && rpc.result.isError) throw new Error('MCP tool error: ' + ((rpc.result.content && rpc.result.content[0] && rpc.result.content[0].text) || 'unknown'));
const ws = JSON.parse(rpc.result.content[0].text);
if (ws.error) throw new Error('open_pdf: ' + ws.error);
const wid = ws.summary.workspace_id;
return [{ json: {
  workspace_id: wid,
  fields: ws.fields.map(f => ({ id: f.id, name: f.name || '', type: f.type, confidence: f.confidence })),
  previewBody: { jsonrpc: '2.0', id: 3, method: 'tools/call', params: { name: 'render_preview', arguments: { workspace_id: wid } } },
} }];

const rpc = $input.first().json;
if (rpc.error) throw new Error('MCP transport error: ' + JSON.stringify(rpc.error));
if (rpc.result && rpc.result.isError) throw new Error('MCP tool error: ' + ((rpc.result.content && rpc.result.content[0] && rpc.result.content[0].text) || 'unknown'));
// The rendered form (boxes labelled with field ids) + the field list with
// each box's detector confidence + the user's data -> a vision request.
// The confidence + false-positive/false-negative warning is what stops the
// model filling spurious boxes (e.g. a stray box drawn over a printed digit).
const img = rpc.result.content.find(c => c.type === 'image');
if (!img) throw new Error('render_preview returned no image.');
const parsed = $('Parse open_pdf').item.json;
const raw = $('On form submission').first().json['Data JSON'];
let data; try { data = JSON.parse(raw); } catch (e) { throw new Error('Data JSON must be valid JSON.'); }

const fieldList = parsed.fields.map(f => {
  const c = (typeof f.confidence === 'number') ? ` confidence ${f.confidence.toFixed(2)}` : '';
  return f.name ? `${f.id} (${f.name};${c})` : `${f.id} (${c.trim()})`;
}).join('; ');
const prompt = [
  'You are filling a PDF form. The image shows the form with each detected input box outlined and labelled with its field id.',
  'Detected fields and the detector\u2019s confidence that each box is a REAL input field:',
  fieldList + '.',
  '',
  'IMPORTANT \u2014 detection is imperfect:',
  '- FALSE POSITIVES: some boxes are not real inputs (e.g. a stray box drawn over printed text or a number). Low-confidence boxes are the usual suspects. Do NOT put a value in a box unless you are confident it is the correct place for that value.',
  '- FALSE NEGATIVES: some real fields may be missing entirely. If a value has no clearly-correct box, OMIT it \u2014 never force it into a wrong or low-confidence box.',
  '',
  'Put this data into the form: ' + JSON.stringify(data) + '.',
  'Return ONLY a JSON object mapping field_id -> string value, for the boxes where the value clearly belongs. Do not invent ids that are not in the list. For a checkbox use "x".',
].join('\n');

const body = {
  model: $('Config').item.json.model || 'google/gemini-3.1-flash-lite',
  messages: [{ role: 'user', content: [
    { type: 'text', text: prompt },
    { type: 'image_url', image_url: { url: `data:${img.mimeType};base64,${img.data}` } },
  ] }],
  response_format: { type: 'json_object' },
  max_tokens: 800,
  temperature: 0,
};
return [{ json: { workspace_id: parsed.workspace_id, requestBody: body } }];

const msg = $input.first().json.choices?.[0]?.message?.content;
if (!msg) throw new Error('The vision model returned no content.');
let map; try { map = JSON.parse(msg); } catch (e) { throw new Error('Model did not return JSON: ' + msg.slice(0, 200)); }
const wid = $('Build vision request').item.json.workspace_id;
const valid = new Set($('Parse open_pdf').item.json.fields.map(f => f.id));
const values = {};
for (const [k, v] of Object.entries(map)) if (valid.has(k)) values[k] = String(v);
if (!Object.keys(values).length) throw new Error('The model mapped nothing to valid field ids.');
return [{ json: { workspace_id: wid, values, fillBody: { jsonrpc: '2.0', id: 4, method: 'tools/call', params: { name: 'fill_pdf', arguments: { workspace_id: wid, values } } } } }];

const rpc = $input.first().json;
if (rpc.error) throw new Error('MCP transport error: ' + JSON.stringify(rpc.error));
if (rpc.result && rpc.result.isError) throw new Error('MCP tool error: ' + ((rpc.result.content && rpc.result.content[0] && rpc.result.content[0].text) || 'unknown'));
const out = JSON.parse(rpc.result.content[0].text);
if (out.error) throw new Error('fill_pdf: ' + out.error);
return [{ json: { download_url: out.download_url, output_mode: out.output_mode, filled_fields: out.filled_fields, warnings: out.warnings || null } }];
